package com.agrios.platform.serviceappointment.domain;
import jakarta.persistence.*; import java.time.Instant; import java.util.UUID; import org.hibernate.annotations.JdbcTypeCode; import org.hibernate.type.SqlTypes;
@Entity @Table(name="appointment_visit_note",schema="service") public class AppointmentVisitNoteEntity { @Id private UUID id; @Column(nullable=false) private UUID appointmentId; @Column(nullable=false) private UUID providerId; @Column(columnDefinition="text") private String diagnosisSummary; @Column(nullable=false,columnDefinition="text") private String recommendationText; @JdbcTypeCode(SqlTypes.JSON) @Column(nullable=false,columnDefinition="jsonb") private String prescriptionDetails; @Column(nullable=false) private boolean followUpRequired; private Instant followUpDueAt; @JdbcTypeCode(SqlTypes.JSON) @Column(nullable=false,columnDefinition="jsonb") private String attachmentReferences; @Column(nullable=false) private Instant createdAt; protected AppointmentVisitNoteEntity(){} public static AppointmentVisitNoteEntity create(UUID appointment,UUID provider,String diagnosis,String recommendation,String prescription,boolean followUp,Instant due,String attachments){var v=new AppointmentVisitNoteEntity();v.id=UUID.randomUUID();v.appointmentId=appointment;v.providerId=provider;v.diagnosisSummary=diagnosis;v.recommendationText=recommendation;v.prescriptionDetails=prescription;v.followUpRequired=followUp;v.followUpDueAt=due;v.attachmentReferences=attachments;v.createdAt=Instant.now();return v;}}
